<?php
\CrediTrack\Application\Notification_Service::refresh();
$notices = $wpdb->get_results( $wpdb->prepare( "SELECT * FROM {$wpdb->prefix}ct_notifications WHERE user_id=%d AND dismissed_at IS NULL ORDER BY read_at IS NULL DESC,created_at DESC LIMIT 100", get_current_user_id() ) );
?><div class="ct-titlebar"><div><h1>Notifications</h1><div class="ct-muted">Due and overdue repayment activity.</div></div></div><div class="ct-notice-list"><?php foreach ( $notices as $notice ) { ?><article class="ct-card ct-notice <?php echo $notice->read_at ? '' : 'unread'; ?>"><div><h2><?php echo esc_html( $notice->title ); ?></h2><p><?php echo esc_html( $notice->message ); ?></p><small class="ct-muted"><?php echo esc_html( $notice->created_at ); ?></small></div><div class="ct-actions"><?php if ( ! $notice->read_at ) { ?><form method="post" action="<?php echo esc_url( admin_url( 'admin-post.php' ) ); ?>"><?php wp_nonce_field( 'creditrack_action' ); ?><input type="hidden" name="action" value="creditrack_notification_action"><input type="hidden" name="notification_id" value="<?php echo esc_attr( $notice->id ); ?>"><input type="hidden" name="notification_action" value="read"><button type="submit">Mark read</button></form><?php } ?><form method="post" action="<?php echo esc_url( admin_url( 'admin-post.php' ) ); ?>"><?php wp_nonce_field( 'creditrack_action' ); ?><input type="hidden" name="action" value="creditrack_notification_action"><input type="hidden" name="notification_id" value="<?php echo esc_attr( $notice->id ); ?>"><input type="hidden" name="notification_action" value="dismiss"><button class="ct-button secondary" type="submit">Dismiss</button></form></div></article><?php } if ( ! $notices ) { ?><div class="ct-card">You are all caught up.</div><?php } ?></div>
